class PaymentModule {
  constructor(config = {}) {
    this.config = {
      providerBaseUrl: config.providerBaseUrl || '',
      providerApiKey: config.providerApiKey || '',
      telemetryEnabled: config.telemetryEnabled ?? true,
      redactTelemetry: config.redactTelemetry ?? true,
      secureStoreService: config.secureStoreService || 'com.example.paymentmodule',
      timeoutMs: config.timeoutMs || DEFAULT_TIMEOUT_MS,
      appId: config.appId || 'app',
    };

    this.telemetry = new Telemetry({
      enabled: this.config.telemetryEnabled,
      redact: this.config.redactTelemetry,
    });

    this.store = new SecureStore({ service: this.config.secureStoreService });

    this.provider = new PaymentProviderClient({
      baseUrl: this.config.providerBaseUrl,
      apiKey: this.config.providerApiKey,
      timeoutMs: this.config.timeoutMs,
      telemetry: this.telemetry,
    });

    this.iap = new IapManager({ telemetry: this.telemetry });

    this.sessionId = randomId('sess');
    this.deviceIdPromise = null;
    this.appStateSub = null;
  }

  async init() {
    this.telemetry.log('module_init', { platform: Platform.OS, sessionId: this.sessionId });
    this.appStateSub = AppState.addEventListener('change', (state) => {
      this.telemetry.log('app_state', { state });
    });
    if (this.iap.isAvailable()) {
      try {
        await this.iap.init();
      } catch (e) {
        this.telemetry.log('iap_init_error', { message: e?.message });
      }
    }
  }

  async shutdown() {
    try {
      this.appStateSub?.remove?.();
    } catch {}
    this.appStateSub = null;
    try {
      await this.iap.end();
    } catch {}
  }

  async getDeviceId() {
    if (this.deviceIdPromise) return this.deviceIdPromise;
    this.deviceIdPromise = (async () => {
      if (DeviceInfo?.getUniqueId) {
        try {
          const id = await DeviceInfo.getUniqueId();
          return id;
        } catch {}
      }
      const cached = await this.store.getItem('device_id');
      if (cached) return cached;
      const id = randomId('dev');
      await this.store.setItem('device_id', id);
      return id;
    })();
    return this.deviceIdPromise;
  }

  async getAccountToken({ userId } = {}) {
    const deviceId = await this.getDeviceId();
    const base = stableStringify({
      appId: this.config.appId,
      userId: userId || 'anonymous',
      deviceId,
      platform: Platform.OS,
    });
    const hash = (await sha256Hex(base)) || randomId('acct');
    return hash;
  }

  async createIdempotencyKey(scope, payload) {
    const deviceId = await this.getDeviceId();
    const msg = stableStringify({
      scope,
      payload,
      deviceId,
      sessionId: this.sessionId,
      ts: Math.floor(Date.now() / 1000),
    });
    const secret = (await this.store.getItem('idem_secret')) || randomId('idemsec');
    if (!(await this.store.getItem('idem_secret'))) await this.store.setItem('idem_secret', secret);
    const sig = (await hmacSha256Hex(secret, msg)) || randomId('idem');
    return `${scope}_${sig}`;
  }

  async listIapProducts(productIds) {
    if (!this.iap.isAvailable()) throw new Error('IAP not available (missing react-native-iap)');
    return this.iap.getProducts(productIds);
  }

  async purchaseIapProduct(productId, { userId, consumable = false } = {}) {
    if (!this.iap.isAvailable()) throw new Error('IAP not available (missing react-native-iap)');
    const accountToken = await this.getAccountToken({ userId });

    const purchase = await this.iap.requestPurchase(productId, { accountToken });

    const receipt = purchase?.transactionReceipt;
    const transactionId = purchase?.transactionId || purchase?.purchaseToken || randomId('tx');

    if (!receipt) {
      this.telemetry.log('iap_missing_receipt', { productId, transactionId });
      throw new Error('Missing receipt');
    }

    const idempotencyKey = await this.createIdempotencyKey('iap_verify', {
      productId,
      transactionId,
    });

    const verification = await this.provider.verifyIapReceipt({
      platform: Platform.OS,
      productId,
      receipt,
      transactionId,
      idempotencyKey,
    });

    await this.iap.finishTransaction(purchase, { isConsumable: !!consumable });

    return {
      ok: true,
      type: 'iap',
      productId,
      transactionId,
      verification,
    };
  }

  async restoreIapPurchases({ userId } = {}) {
    if (!this.iap.isAvailable()) throw new Error('IAP not available (missing react-native-iap)');
    const accountToken = await this.getAccountToken({ userId });
    const purchases = await this.iap.getAvailablePurchases();
    return { ok: true, type: 'iap_restore', accountToken, purchases };
  }

  async createWalletTransaction({
    amount,
    currency = 'USD',
    source,
    metadata,
    userId,
  } = {}) {
    if (!amount || typeof amount !== 'number') throw new Error('Invalid amount');
    if (!currency) throw new Error('Invalid currency');
    if (!source || typeof source !== 'object') throw new Error('Invalid source');

    const accountToken = await this.getAccountToken({ userId });

    const safeMetadata = metadata && typeof metadata === 'object' ? metadata : undefined;

    const idempotencyKey = await this.createIdempotencyKey('wallet_tx', {
      amount,
      currency,
      accountToken,
    });

    const res = await this.provider.createWalletTransaction({
      amount,
      currency,
      source: { ...source, accountToken },
      metadata: safeMetadata,
      idempotencyKey,
    });

    return { ok: true, type: 'wallet', result: res };
  }

  getTelemetryLogs() {
    return this.telemetry.getLogs();
  }

  clearTelemetry() {
    this.telemetry.clear();
  }
}

export function createPaymentModule(config) {
  const module = new PaymentModule(config);
  return module;
}

export function usePaymentModule(config) {
  const moduleRef = useRef(null);
  if (!moduleRef.current) moduleRef.current = createPaymentModule(config);

  const [ready, setReady] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        await moduleRef.current.init();
        if (mounted) setReady(true);
      } catch (e) {
        if (mounted) setError(e);
      }
    })();
    return () => {
      mounted = false;
      moduleRef.current.shutdown().catch(() => {});
    };
  }, []);

  return { payment: moduleRef.current, ready, error };
}

export function PaymentDemoScreen({
  providerBaseUrl,
  providerApiKey,
  productIds = [],
  userId,
}) {
  const { payment, ready, error } = usePaymentModule({
    providerBaseUrl,
    providerApiKey,
    telemetryEnabled: true,
    redactTelemetry: true,
    appId: 'demo',
  });

  const [loading, setLoading] = useState(false);
  const [products, setProducts] = useState([]);
  const [result, setResult] = useState(null);

  const canIap = useMemo(() => !!RNIap, []);

  const loadProducts = useCallback(async () => {
    if (!canIap) return;
    setLoading(true);
    try {
      const p = await payment.listIapProducts(productIds);
      setProducts(p);
    } catch (e) {
      Alert.alert('Error', e?.message || 'Failed to load products');
    } finally {
      setLoading(false);
    }
  }, [payment, productIds, canIap]);

  useEffect(() => {
    if (ready && canIap && productIds?.length) loadProducts();
  }, [ready, canIap, productIds?.length]);

  const onBuy = useCallback(
    async (productId) => {
      setLoading(true);
      setResult(null);
      try {
        const res = await payment.purchaseIapProduct(productId, { userId, consumable: false });
        setResult(res);
        Alert.alert('Success', `Purchased ${productId}`);
      } catch (e) {
        Alert.alert('Purchase failed', e?.message || 'Unknown error');
      } finally {
        setLoading(false);
      }
    },
    [payment, userId]
  );

  const onWalletTx = useCallback(async () => {
    setLoading(true);
    setResult(null);
    try {
      const res = await payment.createWalletTransaction({
        amount: 4.99,
        currency: 'USD',
        source: {
          type: 'digital_wallet',
          provider: Platform.OS === 'ios' ? 'apple_pay' : 'google_pay',
        },
        metadata: { reason: 'demo_topup' },
        userId,
      });
      setResult(res);
      Alert.alert('Success', 'Wallet transaction created');
    } catch (e) {
      Alert.alert('Wallet failed', e?.message || 'Unknown error');
    } finally {
      setLoading(false);
    }
  }, [payment, userId]);

  const onRestore = useCallback(async () => {
    setLoading(true);
    setResult(null);
    try {
      const res = await payment.restoreIapPurchases({ userId });
      setResult(res);
      Alert.alert('Restored', `Found ${res?.purchases?.length || 0} purchases`);
    } catch (e) {
      Alert.alert('Restore failed', e?.message || 'Unknown error');
    } finally {
      setLoading(false);
    }
  }, [payment, userId]);

  const logs = payment.getTelemetryLogs();

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Payment Module Demo</Text>

      {!ready && (
        <View style={styles.row}>
          <ActivityIndicator />
          <Text style={styles.muted}> Initializing…</Text>
        </View>
      )}

      {error && <Text style={styles.error}>Init error: {String(error?.message || error)}</Text>}

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>In-App Purchases</Text>
        {!canIap && <Text style={styles.muted}>react-native-iap not installed.</Text>}
        {canIap && (
          <>
            <TouchableOpacity
              style={[styles.button, loading && styles.buttonDisabled]}
              disabled={loading}
              onPress={loadProducts}
            >
              <Text style={styles.buttonText}>Reload Products</Text>
            </TouchableOpacity>

            {products?.length ? (
              products.map((p) => (
                <View key={p.productId} style={styles.productRow}>
                  <View style={{ flex: 1 }}>
                    <Text style={styles.productTitle}>{p.title || p.productId}</Text>
                    <Text style={styles.muted}>{p.localizedPrice || p.price}</Text>
                  </View>
                  <TouchableOpacity
                    style={[styles.buttonSmall, loading && styles.buttonDisabled]}
                    disabled={loading}
                    onPress={() => onBuy(p.productId)}
                  >
                    <Text style={styles.buttonText}>Buy</Text>
                  </TouchableOpacity>
                </View>
              ))
            ) : (
              <Text style={styles.muted}>No products loaded.</Text>
            )}

            <TouchableOpacity
              style={[styles.button, loading && styles.buttonDisabled]}
              disabled={loading}
              onPress={onRestore}
            >
              <Text style={styles.buttonText}>Restore Purchases</Text>
            </TouchableOpacity>
          </>
        )}
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Digital Wallet</Text>
        <TouchableOpacity
          style={[styles.button, loading && styles.buttonDisabled]}
          disabled={loading}
          onPress={onWalletTx}
        >
          <Text style={styles.buttonText}>Create Wallet Transaction</Text>
        </TouchableOpacity>
        <Text style={styles.muted}>
          Note: This demo calls your backend provider endpoint; it does not collect card data.
        </Text>
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Last Result</Text>
        <Text style={styles.code} numberOfLines={10}>
          {result ? stableStringify(result) : '—'}
        </Text>
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Telemetry (Redacted)</Text>
        <Text style={styles.code} numberOfLines={10}>
          {logs?.length ? stableStringify(logs.slice(-10)) : '—'}
        </Text>
        <TouchableOpacity
          style={[styles.button, loading && styles.buttonDisabled]}
          disabled={loading}
          onPress={() => payment.clearTelemetry()}
        >
          <Text style={styles.buttonText}>Clear Telemetry</Text>
        </TouchableOpacity>
      </View>
    </View>
  );
}

